class ModelExtractor:
    """Extrait les informations de modeles depuis les resultats de recherche."""

    def __init__(self, llm: LLMClient):
        self.llm = llm

    def extract_models(self, search_results: List[SearchResult], task: str) -> List[ModelInfo]:
        """Utilise le LLM pour extraire les modeles pertinents."""
        context = "\n".join([
            f"- {r.title}: {r.snippet} ({r.url})"
            for r in search_results[:5]
        ])

        prompt = f"""Analyse ces resultats de recherche pour la tache: {task}

RESULTATS:
{context}

Extrait les 2-3 modeles les plus pertinents avec leurs informations.
Format JSON:
[
  {{"name": "...", "paper_url": "...", "description": "...", "code_url": "..."}}
]

JSON:"""

        response = self.llm.generate(prompt, temperature=0.2)

        # Extract JSON
        try:
            match = re.search(r'\[.*\]', response, re.DOTALL)
            if match:
                data = json.loads(match.group(0))
                return [ModelInfo(**m) for m in data]
        except:
            pass
        return []

print("Classe ModelExtractor definie : extraction de modeles pertinents depuis resultats de recherche via LLM")

class AblationStudy:
    """Simule des etudes d'ablation pour prioriser les ameliorations."""

    def __init__(self, llm: LLMClient):
        self.llm = llm

    def estimate_importance(self, blocks: List[CodeBlock], task: str) -> List[CodeBlock]:
        """Estime l'importance relative de chaque bloc."""
        blocks_desc = "\n".join([
            f"- {b.id}: {b.name} - {b.description[:50]}"
            for b in blocks
        ])

        prompt = f"""Estime l'importance de chaque bloc pour la tache: {task}

BLOCS:
{blocks_desc}

Donne un score d'importance de 0.0 a 1.0 pour chaque bloc.
Format JSON:
[
  {{"id": "block1", "importance": 0.9}},
  {{"id": "block2", "importance": 0.6}}
]

JSON:"""

        response = self.llm.generate(prompt, temperature=0.2)

        try:
            match = re.search(r'\[.*\]', response, re.DOTALL)
            if match:
                data = json.loads(match.group(0))
                importance_map = {d['id']: d['importance'] for d in data}
                for block in blocks:
                    block.importance = importance_map.get(block.id, 0.5)
        except:
            # Default importance
            for i, block in enumerate(blocks):
                block.importance = 0.8 - i * 0.1

        return sorted(blocks, key=lambda b: b.importance, reverse=True)

print("Classe AblationStudy definie : estimation de l'importance relative des blocs (0.0-1.0) via LLM")

class TargetedRefiner:
    """Raffine de maniere ciblee les composants critiques."""

    def __init__(self, llm: LLMClient):
        self.llm = llm

    def refine_block(self, block: CodeBlock, task: str, current_score: float) -> str:
        """Genere une version amelioree d'un bloc."""
        prompt = f"""Ameliore ce bloc de code ML pour la tache: {task}

BLOC: {block.name}
DESCRIPTION: {block.description}
CODE ACTUEL:
```python
{block.code[:1000]}
```

SCORE ACTUEL: {current_score:.3f}

Genere une version amelioree qui pourrait augmenter le score.
Focus sur les optimisations simples et efficaces.

```python
# Code ameliore
```"""

        response = self.llm.generate(prompt, temperature=0.3)
        match = re.search(r'```python\s*(.*?)\s*```', response, re.DOTALL)
        return match.group(1).strip() if match else block.code

print("Classe TargetedRefiner definie : raffinement cible de blocs critiques via LLM")

@dataclass
class CompetitionInfo:
    name: str
    task: str
    metric: str
    description: str
    data_description: str

class KaggleSimulator:
    def get_competition_info(self) -> CompetitionInfo:
        return CompetitionInfo(
            name='Tabular Playground Series',
            task='binary classification',
            metric='AUC-ROC',
            description='Predict customer churn based on tabular features',
            data_description='20 features numeriques et categoriques, 10000 exemples'
        )

    def generate_sample_data(self, n_samples: int = 500) -> pd.DataFrame:
        np.random.seed(42)
        return pd.DataFrame({
            'customer_id': range(n_samples),
            'age': np.random.randint(18, 80, n_samples),
            'tenure': np.random.randint(1, 72, n_samples),
            'monthly_charges': np.random.uniform(20, 150, n_samples).round(2),
            'total_charges': np.random.uniform(100, 8000, n_samples).round(2),
            'contract_type': np.random.choice(['Month-to-month', 'One year', 'Two year'], n_samples),
            'internet_service': np.random.choice(['DSL', 'Fiber', 'No'], n_samples),
            'target': np.random.randint(0, 2, n_samples)
        })

print("Dataclasses definies : CompetitionInfo (nom, tache, metrique), KaggleSimulator (info + donnees synthetiques)")

@dataclass
class SQLQuery:
    sql: str
    explanation: str
    tables_used: List[str]

class NL2SQLTranslator:
    def __init__(self, llm: LLMClient):
        self.llm = llm

    def translate(self, question: str, schema: Dict) -> SQLQuery:
        schema_desc = self._format_schema(schema)
        prompt = f"""Convertis cette question en SQL BigQuery.

SCHEMA:
{schema_desc}

QUESTION: {question}

EXPLANATION: [explication]
SQL:
```sql
[requete]
```"""
        response = self.llm.generate(prompt, temperature=0.2)
        explanation = ''
        sql = ''
        if 'EXPLANATION:' in response:
            match = re.search(r'EXPLANATION:\s*(.+?)(?=SQL:|$)', response, re.DOTALL)
            explanation = match.group(1).strip() if match else ''
        sql_match = re.search(r'```sql\s*(.*?)\s*```', response, re.DOTALL)
        sql = sql_match.group(1).strip() if sql_match else ''
        return SQLQuery(sql=sql, explanation=explanation, tables_used=[])

    def _format_schema(self, schema: Dict) -> str:
        return '\n'.join([f'Table {t}: {cols}' for t, cols in schema.items()])

print("Classes definies : SQLQuery (dataclass), NL2SQLTranslator (langage naturel vers SQL BigQuery)")

@dataclass
class PythonCode:
    code: str
    explanation: str

class NL2PyTranslator:
    def __init__(self, llm: LLMClient):
        self.llm = llm

    def translate(self, question: str, data_context: str) -> PythonCode:
        prompt = f"""Genere du code Python pour: {question}

CONTEXTE: {data_context}

EXPLANATION: [explication]
CODE:
```python
[code]
```"""
        response = self.llm.generate(prompt, temperature=0.2)
        explanation = ''
        code = ''
        if 'EXPLANATION:' in response:
            match = re.search(r'EXPLANATION:\s*(.+?)(?=CODE:|$)', response, re.DOTALL)
            explanation = match.group(1).strip() if match else ''
        code_match = re.search(r'```python\s*(.*?)\s*```', response, re.DOTALL)
        code = code_match.group(1).strip() if code_match else ''
        return PythonCode(code=code, explanation=explanation)

print("Classes definies : PythonCode (dataclass), NL2PyTranslator (langage naturel vers code Python)")

class DataScienceAgent:
    def __init__(self):
        self.llm = LLMClient()
        self.nl2sql = NL2SQLTranslator(self.llm)
        self.nl2py = NL2PyTranslator(self.llm)

    def analyze(self, question: str, schema: Dict, mode: str = 'sql') -> Dict:
        print(f'[AGENT] Question: {question}')
        print(f'[AGENT] Mode: {mode}')
        if mode == 'sql':
            result = self.nl2sql.translate(question, schema)
            return {'type': 'sql', 'query': result.sql, 'explanation': result.explanation}
        elif mode == 'python':
            data_context = self.nl2sql._format_schema(schema)
            result = self.nl2py.translate(question, data_context)
            return {'type': 'python', 'code': result.code, 'explanation': result.explanation}
        return {'error': 'Mode non supporte'}

print("Classe DataScienceAgent definie : orchestrateur NL2SQL/NL2Py pour BigQuery")

